	// Verify response
	require.NotNil(t, msg.response, "should have response")

	var responseEntities []graph.EntityState
	err = json.Unmarshal(msg.response, &responseEntities)
	require.NoError(t, err, "response should be valid EntityState array JSON")

	// Should return only the 2 entities that exist (partial success)
	assert.Equal(t, 2, len(responseEntities), "should return only existing entities")

	// Verify the returned entities are the correct ones
