	for _, e := range responseEntities {
		ids[e.ID] = true
	}

	assert.True(t, ids["c360.platform.robotics.mav1.drone.001"], "should include drone.001")
	assert.False(t, ids["c360.platform.robotics.mav1.drone.002"], "should NOT include non-existent drone.002")
	assert.True(t, ids["c360.platform.robotics.mav1.drone.003"], "should include drone.003")
